```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int pipefd[2];
    pid_t pid;

    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur lors de la création du pipe" << std::endl;
        return 1;
    }

    pid = fork();

    if (pid == -1) {
        std::cerr << "Erreur lors de la création du processus fils" << std::endl;
        return 1;
    }

    if (pid == 0) { // C'est le processus fils
        // Rediriger l'entrée et la sortie du processus vers le pipe
        close(pipefd[1]); // Fermer l'écriture côté fils
        dup2(pipefd[0], STDIN_FILENO); // Rediriger l'entrée vers le pipe
        close(pipefd[0]); // Fermer le descripteur de lecture du pipe

        close(pipefd[0]); // Fermer l'entrée du pipe (déjà redirigée)
        dup2(pipefd[1], STDOUT_FILENO); // Rediriger la sortie vers le pipe
        close(pipefd[1]); // Fermer le descripteur d'écriture du pipe

        // Maintenant, le processus fils peut lire de stdin et écrire vers stdout
        // comme s'il s'agissait d'un autre flux standard
        // Par exemple, vous pourriez exécuter une commande avec pclose ici
    } else { // C'est le processus père
        close(pipefd[0]); // Fermer la lecture côté père
        // Maintenant, le processus père peut écrire vers le pipe
        // et lire les résultats du processus fils
    }

    return 0;
}
```

Ce code crée un nouveau processus et connecte son entrée et sa sortie au pipe.

